#include <stdio.h>
#include <stdlib.h>

int countLessOrEqual(int** matrix, int m, int n, int x) {
    int cnt = 0, c = n - 1;
    for (int r = 0; r < m; ++r) {
        while (c >= 0 && matrix[r][c] > x) --c;
        cnt += (c + 1);
    }
    return cnt;
}

int kthSmallest(int** matrix, int m, int n, int k) {
    int left = matrix[0][0], right = matrix[m - 1][n - 1], ans = -1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (countLessOrEqual(matrix, m, n, mid) >= k) {
            ans = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return ans;
}

int main() {
    int n, k;
    scanf("%d %d", &n, &k);

    int** flowers = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; ++i) {
        flowers[i] = (int*)malloc(n * sizeof(int));
        for (int j = 0; j < n; ++j) {
            scanf("%d", &flowers[i][j]);
        }
    }

    printf("%d\n", kthSmallest(flowers, n, n, k));

    for (int i = 0; i < n; ++i) {
        free(flowers[i]);
    }
