function countLessOrEqual(matrix, x) {
    let cnt = 0;
    const n = matrix.length;
    let c = n - 1; // Start from the last column

    for (let r = 0; r < n; r++) {
        while (c >= 0 && matrix[r][c] > x) {
            c--; // Move left in the current row
        }
        cnt += c + 1; // Add the number of elements <= x in this row
    }
    return cnt;
}

function kthSmallest(matrix, k) {
    const n = matrix.length;
    let left = matrix[0][0];
    let right = matrix[n - 1][n - 1];
    let ans = -1;

    while (left <= right) {
        const mid = left + Math.floor((right - left) / 2);
        const count = countLessOrEqual(matrix, mid);

        if (count >= k) {
            ans = mid; // Possible answer
            right = mid - 1; // Look for a smaller value
        } else {
            left = mid + 1; // Look for a larger value
        }
    }
    return ans;
}

