const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let n, k;
let flowers = [];
let lineCount = 0;

rl.on('line', (line) => {
    if (lineCount === 0) {
        // First line: Read n and k
        [n, k] = line.split(' ').map(Number);
    } else {
        // Subsequent lines: Read the matrix rows
        flowers.push(line.split(' ').map(Number));
    }
    lineCount++;

    // If all rows are read, close the input stream and compute the result
    if (lineCount === n + 1) {
        rl.close();
        console.log(kthSmallest(flowers, k));
    }
});
